 &#34;; do{ cout&lt;&lt;&#34;	&#34;&lt;&lt;&#34;Enter the value of Avg. radius (r) of centrifugal tube:&#34;; cin&gt;&gt;r; e=0.00001119; b=e*r cout&lt;&lt;&#34;	&#34;&lt;&lt;&#34;Enter the value of HYPERGRAVITY (RCF) e.g. 5 for 5g:&#34;; cin&gt;&gt;RCF; rpm=RCF/b; cout&lt;&lt;&#34;
